#include <iostream>
#include <vector>

void analyze() {
    std::vector<int> collection = {1, 2, 3};
    try {
        int val = collection.at(5);
        std::cout << val << std::endl;
    } catch (const std::out_of_range& e) {
        std::cerr << "Index out of bounds" << std::endl;
    }
}

int main() {
    analyze();
    return 0;
}

