#include <iostream>

int analyze(int a, int b) {
    if (b == 0) {
        std::cerr << "Division by zero error" << std::endl;
        return 0;
    }
    int val = a / b;
    return val;
}

int main() {
    std::cout << analyze(10, 0) << std::endl;
    return 0;
